#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint32_t X;
        scanf("%u", &X);
        uint32_t y = X + 1;               // y >= 1
        int m = 0;
        while ((1U << (m + 1)) <= y) ++m; // find floor(log2 y)
        uint32_t ans = 1U << m;
        printf("%u\n", ans);
    }
    return 0;
}

